    fn roundtrip_2d() {
        let (w, h) = (8, 4);
        let mut x: Vec<Complex> = (0..w * h)
            .map(|i| Complex::new((i % 5) as f32, 0.0))
            .collect();
        let orig = x.clone();
        fft_2d(&mut x, w, h, false);
        fft_2d(&mut x, w, h, true);
        for (a, b) in x.iter().zip(orig.iter()) {
            assert!((a.re - b.re).abs() < 1e-3);
        }
