    fn normalize_range_is_0_to_255() {
        let v = vec![0.0f32, 0.25, 0.5, 0.75, 1.0];
        let u = normalize_to_u8(&v);
        assert_eq!(u[0], 0);
        assert_eq!(u[4], 255);
        // Monotonic non-decreasing mapping (0..=1 -> 0..=255); range is guaranteed by u8.
        assert!(u.windows(2).all(|w| w[0] <= w[1]));
    }

