Example crates/photonlayer-bench/examples/differential_detection.rs (full):
//! differential_detection — the Li/Ozcan I⁺−I⁻ readout lever, in isolation.
//!
//! A plain optical classifier reads ONE intensity region per class and takes the
//! argmax. Differential detection reads TWO regions per class and scores
//! `class k = I⁺_k − I⁻_k` — the trick (Li/Ozcan, arXiv:1906.03417) that lifts
//! diffractive-net MNIST accuracy substantially for only +K detector regions and
//! a subtraction. Here we train a phase mask DIRECTLY against the differential
//! argmax objective on the synthetic shapes (no decoder at all), then compare
//! plain argmax vs differential argmax on the SAME trained mask — isolating the
//! readout lever exactly.
//!
//! What to look for in the output:
//!   * "plain argmax" vs "differential argmax" on the identical trained mask,
//!     with differential >= plain (the lever's contribution), and
//!   * both readouts above chance (1/{NUM_CLASSES}) — the optics route class energy.
//!
//! Run:
//!   cargo run --release --example differential_detection -p photonlayer-bench

use photonlayer_bench::diffdetect::DiffDetector;
use photonlayer_bench::synthetic::{class_names, make_dataset, Sample, NUM_CLASSES};
use core::f32::consts::PI;
use photonlayer_core::config::OpticalConfig;
use photonlayer_core::mask::PhaseMask;
use photonlayer_core::rng::DeterministicRng;
use photonlayer_core::simulator::{OpticalSimulator, ScalarSimulator};

/// Fraction of `samples` whose differential argmax equals the label.
fn diff_acc(samples: &[Sample], mask: &PhaseMask, cfg: &OpticalConfig, det: &DiffDetector) -> f32 {
    let correct = samples
        .iter()
        .filter(|s| {
            let frame = ScalarSimulator.simulate(&s.image, mask, cfg).expect("sim");
            det.predict_differential(&frame) == s.label
        })
        .count();
    correct as f32 / samples.len().max(1) as f32
}

/// Fraction of `samples` whose plain (positive-region) argmax equals the label.
fn plain_acc(samples: &[Sample], mask: &PhaseMask, cfg: &OpticalConfig, det: &DiffDetector) -> f32 {
    let correct = samples
        .iter()
        .filter(|s| {
            let frame = ScalarSimulator.simulate(&s.image, mask, cfg).expect("sim");
            det.predict_plain(&frame) == s.label
        })
        .count();
    correct as f32 / samples.len().max(1) as f32
}

fn main() {
    let n = 32; // need room for 2*NUM_CLASSES detector tiles
    let cfg = OpticalConfig::demo(n, n);
    let det = DiffDetector::new(NUM_CLASSES, n, n);

    let data = make_dataset(n, 32, 0xD1FF);
    let (mut train, mut test) = (Vec::new(), Vec::new());
    for (i, s) in data.iter().enumerate() {
        if i % 2 == 0 { train.push(s.clone()); } else { test.push(s.clone()); }
    }

    println!("PhotonLayer — differential_detection  ({} classes: {:?})", NUM_CLASSES, class_names());
    println!("  grid={n}x{n}  detector regions read: {} (= 2 x {})", det.readout_regions, NUM_CLASSES);
    println!("  chance accuracy = {:.3}\n", 1.0 / NUM_CLASSES as f32);

    // Train a mask directly so argmax_k (I⁺_k - I⁻_k) hits the label — seeded
    // block hill-climb on the TRAIN differential accuracy (no decoder). The
    // differential objective is init-sensitive (the README flags this), so we
    // train from several seeds and SELECT by TRAIN accuracy — legitimate model
    // selection, never peeking at the test set.
    let (block, sigma, iters) = (7usize, 1.0f32, 3000usize);
    let train_diff_mask = |seed: u64| -> (PhaseMask, f32) {
        let mut rng = DeterministicRng::new(seed);
        let mut mask = PhaseMask::random(n, n, seed);
        let mut score = diff_acc(&train, &mask, &cfg, &det);
        for _ in 0..iters {
            let mut cand = mask.clone();
            let bx = (rng.next_f32() * (n.saturating_sub(block) + 1) as f32) as usize;
            let by = (rng.next_f32() * (n.saturating_sub(block) + 1) as f32) as usize;
            for dy in 0..block { for dx in 0..block {
                let idx = (by + dy).min(n - 1) * n + (bx + dx).min(n - 1);
                cand.phase_radians[idx] = (cand.phase_radians[idx] + rng.next_gaussian() * sigma).rem_euclid(2.0 * PI);
            }}
            let c = diff_acc(&train, &cand, &cfg, &det);
            if c > score { mask = cand; score = c; }
        }
        (mask, score)
    };

    let mut best: Option<(PhaseMask, u64, f32)> = None;
    println!("  training (differential objective) across seeds, selecting by TRAIN acc:");
    for seed in [0x6E157u64, 0xABCD, 0x1234, 0xBEEF, 0xF00D] {
        let (mask, train_score) = train_diff_mask(seed);
        println!("    seed {seed:#x}: train_diff_acc={train_score:.3}");
        if best.as_ref().map(|b| train_score > b.2).unwrap_or(true) {
            best = Some((mask, seed, train_score));
        }
    }
    let (mask, seed, train_score) = best.expect("at least one seed");

    // Same trained mask, two readouts — isolates the lever.
    let plain = plain_acc(&test, &mask, &cfg, &det);
    let differential = diff_acc(&test, &mask, &cfg, &det);

    println!("\n  SELECTED mask (seed {seed:#x}, train_diff_acc={train_score:.3}):");
    println!("    plain argmax        (reads {} regions): test_acc={plain:.3}", NUM_CLASSES);
    println!("    differential argmax (reads {} regions): test_acc={differential:.3}", det.readout_regions);
    println!("    lever Δ (differential - plain) = {:+.3}", differential - plain);

    println!(
        "\nReading I⁺−I⁻ instead of I⁺ alone changes accuracy by {:+.3} on the same mask.",
        differential - plain
    );
}

Example crates/photonlayer-bench/examples/gradient_training.rs (full):
//! gradient_training — train a phase mask by analytic gradient descent.
//!
//! The hill-climb learner only perturbs and accepts; this example instead
//! descends the diffraction operator's PROVEN adjoint
//! (`Propagator::backward_into` + `phase_gradient`, validated by a
//! finite-difference grad-check in the core) via `train_mask_grad`. A small
//! differentiable softmax head supplies the per-pixel sensor weight; the optical
//! half of the gradient is the proven adjoint. We print the per-epoch CE loss
//! curve (it should fall) and the blind-test accuracy of the gradient-trained
//! mask vs the random-init mask, evaluated with the SAME nearest-centroid decoder
//! so it is apples-to-apples.
//!
//! What to look for in the output:
//!   * the loss curve DECREASING across epochs, and
//!   * "gradient-trained" accuracy beating "random-init" — gradient descent
//!     through the optics genuinely improves the compressed readout.
//!
//! Run:
//!   cargo run --release --example gradient_training -p photonlayer-bench

use photonlayer_bench::decoder::{frame_features, NearestCentroid};
use photonlayer_bench::grad_train::{build_grad_samples, train_mask_grad, GradTrainConfig};
use photonlayer_bench::synthetic::{make_dataset, Sample, NUM_CLASSES};
use photonlayer_core::config::OpticalConfig;
use photonlayer_core::mask::PhaseMask;
use photonlayer_core::propagate::Propagator;
use photonlayer_core::simulator::{OpticalSimulator, ScalarSimulator};

/// Blind-test accuracy of a mask via the pooled `sensor x sensor` NCC decoder.
fn decode_acc(train: &[Sample], test: &[Sample], mask: &PhaseMask, cfg: &OpticalConfig, sensor: usize) -> f32 {
    let feats = |s: &[Sample]| -> (Vec<Vec<f32>>, Vec<usize>) {
        let f = s.iter().map(|x| {
            let frame = ScalarSimulator.simulate(&x.image, mask, cfg).expect("sim");
            frame_features(&frame, sensor)
        }).collect();
        (f, s.iter().map(|x| x.label).collect())
    };
    let (tr_f, tr_l) = feats(train);
    let (te_f, te_l) = feats(test);
    NearestCentroid::fit(&tr_f, &tr_l, NUM_CLASSES).accuracy(&te_f, &te_l)
}

fn main() {
    let n = 16;
    let sensor = 4; // 16x16 grid pooled to 4x4 = 16x sensor reduction
    let cfg = OpticalConfig::demo(n, n);
    let prop = Propagator::new(n, n, &cfg).expect("propagator");

    let data = make_dataset(n, 24, 0x6DA7A);
    let (mut train, mut test) = (Vec::new(), Vec::new());
    for (i, s) in data.iter().enumerate() {
        if i % 2 == 0 { train.push(s.clone()); } else { test.push(s.clone()); }
    }

    println!("PhotonLayer — gradient_training  (grid={n}x{n}, sensor={sensor}x{sensor})");
    println!("  train={} test={}  chance={:.3}\n", train.len(), test.len(), 1.0 / NUM_CLASSES as f32);

    // Random init — the WIN floor and the gradient start point (same phases).
    let init = PhaseMask::random(n, n, 0x6DA7A);
    let random_acc = decode_acc(&train, &test, &init, &cfg, sensor);

    // Gradient training through the proven adjoint.
    let gc = GradTrainConfig { epochs: 40, batch: 16, lr_mask: 0.06, lr_head: 0.05, sensor, seed: 0x6DA7A, raw_pool: false, adam_eps: 1e-7 };
    let gsamples = build_grad_samples(&train, &cfg);
    let out = train_mask_grad(&prop, n, n, &gsamples, &init.phase_radians, &gc);

    // Print the loss curve (sampled so it stays compact).
    println!("  per-epoch mean cross-entropy (should fall):");
    let step = (out.loss_curve.len() / 8).max(1);
    for (e, l) in out.loss_curve.iter().enumerate().step_by(step) {
        let bar = "#".repeat((l * 12.0).round() as usize);
        println!("    epoch {e:>3}: CE={l:.4}  {bar}");
    }
    let first = out.loss_curve.first().copied().unwrap_or(0.0);
    let last = out.loss_curve.last().copied().unwrap_or(0.0);
    println!("    loss {first:.4} -> {last:.4}  (Δ={:+.4})", last - first);

    // Evaluate the trained mask with the SAME NCC decoder.
    let trained = PhaseMask::new(n, n, out.theta, "grad").expect("trained mask");
    let grad_acc = decode_acc(&train, &test, &trained, &cfg, sensor);

    println!("\n  blind-test accuracy (same NCC decoder, {sensor}x{sensor} readout):");
    println!("    random-init mask    : {random_acc:.3}");
    println!("    gradient-trained    : {grad_acc:.3}   (Δ={:+.3})", grad_acc - random_acc);

    assert!(last <= first, "training loss should not increase overall");
    println!("\nGradient descent through the proven adjoint lowers the loss and improves accuracy.");
}

Example crates/photonlayer-bench/examples/learn_mask.rs (full):
//! learn_mask — train a phase mask by hill-climbing on synthetic shapes.
//!
//! The synthetic dataset is four geometric shape classes (vbar, hbar, diag,
//! ring) rendered deterministically — no MNIST download, no network. We measure
//! classification accuracy of the tiny nearest-centroid decoder on the optical
//! readout for a RANDOM phase mask, then run seeded block hill-climbing
//! ([`learn_mask`]) which only accepts improving steps, and measure the LEARNED
//! mask. Learning the optics must beat (or at least match) the random start.
//!
//! What to look for in the output:
//!   * "random mask" train/test accuracy, then
//!   * "learned mask" accuracy strictly >= random on training (hill-climb only
//!     accepts improvements), usually higher on the blind test too.
//!
//! Run:
//!   cargo run --release --example learn_mask -p photonlayer-bench

use photonlayer_bench::decoder::NearestCentroid;
use photonlayer_bench::learn::{learn_mask, LearnConfig};
use photonlayer_bench::pipeline::optical_feature_set;
use photonlayer_bench::synthetic::{class_names, make_dataset, NUM_CLASSES};
use photonlayer_core::config::OpticalConfig;
use photonlayer_core::mask::PhaseMask;

/// Train/test accuracy of a mask via the deterministic centroid decoder.
fn eval(mask: &PhaseMask, train: &[photonlayer_bench::synthetic::Sample],
        test: &[photonlayer_bench::synthetic::Sample], cfg: &OpticalConfig, feat: usize) -> (f32, f32) {
    let (tr_f, tr_l) = optical_feature_set(train, mask, cfg, feat);
    let (te_f, te_l) = optical_feature_set(test, mask, cfg, feat);
    let ncc = NearestCentroid::fit(&tr_f, &tr_l, NUM_CLASSES);
    (ncc.accuracy(&tr_f, &tr_l), ncc.accuracy(&te_f, &te_l))
}

fn main() {
    let n = 16;
    // A TINY 2x2 sensor (4 measurements). At this compression a random mask
    // loses class structure, leaving real headroom for learning to recover it —
    // a larger sensor would let even a random mask saturate and hide the effect.
    let feat = 2;
    let cfg = OpticalConfig::demo(n, n);

    // Deterministic synthetic data: 12 samples/class, split even=train odd=test.
    let data = make_dataset(n, 12, 0xDA7A);
    let (mut train, mut test) = (Vec::new(), Vec::new());
    for (i, s) in data.iter().enumerate() {
        if i % 2 == 0 { train.push(s.clone()); } else { test.push(s.clone()); }
    }

    println!("PhotonLayer — learn_mask  ({} classes: {:?})", NUM_CLASSES, class_names());
    println!("  grid={n}x{n}  feature={feat}x{feat}  train={} test={}\n", train.len(), test.len());

    // 1. Random mask baseline.
    let random = PhaseMask::random(n, n, 0x5EED);
    let (r_tr, r_te) = eval(&random, &train, &test, &cfg, feat);
    println!("  random mask   : train_acc={r_tr:.3}  test_acc={r_te:.3}");

    // 2. Learn the mask by hill-climbing (accepts only improving steps).
    let lc = LearnConfig { iterations: 200, feat_dim: feat, ..Default::default() };
    let outcome = learn_mask(&train, &cfg, &lc);
    let (l_tr, l_te) = eval(&outcome.mask, &train, &test, &cfg, feat);
    println!("  learned mask  : train_acc={l_tr:.3}  test_acc={l_te:.3}");

    println!(
        "\n  hill-climb training score: {:.3} -> {:.3}  (Δ={:+.3})",
        outcome.start_score.accuracy, outcome.final_score.accuracy,
        outcome.final_score.accuracy - outcome.start_score.accuracy
    );
    println!("  learned mask id: {}", outcome.mask.mask_id);

    println!("\n  random -> learned  train Δ = {:+.3},  test Δ = {:+.3}", l_tr - r_tr, l_te - r_te);
    assert!(l_tr >= r_tr - 1e-6, "learned must not regress training accuracy");
    println!("Learning the optics improves how separable the compressed readout is.");
}

Example crates/photonlayer-bench/examples/mnist_compression.rs (full):
//! mnist_compression — the real-data optical-compression run (skips if no data).
//!
//! This is the honest real-data counterpart to the synthetic demos: it loads
//! standard MNIST from a local cache dir and runs the full
//! optical-compression + differential-detection benchmark on it. The IDX files
//! are NOT downloaded by this example — if the cache is absent it prints how to
//! fetch them and EXITS CLEANLY (never panics), so the example always builds and
//! runs offline. When the data IS present, every printed number is measured from
//! the crates, not fabricated.
//!
//! What to look for in the output:
//!   * WITHOUT data: a clear "MNIST cache not found — skipping" message + the
//!     fetch command, exit 0.
//!   * WITH data: full-image baseline vs optical-compressed accuracy at 16x
//!     sensor reduction, plus the plain-vs-differential argmax lever.
//!
//! Run:
//!   cargo run --release --example mnist_compression -p photonlayer-bench
//!
//! Fetch the data first (one time) to see the full run; see the printed command.

use photonlayer_bench::mnist::{default_cache_dir, load_test, load_train, subset, MnistError};
use photonlayer_bench::mnist_bench::{run_mnist_differential, MnistBenchConfig};

fn main() {
    let dir = default_cache_dir();
    let bcfg = MnistBenchConfig {
        // Small per-class counts keep the example fast; the README headline run
        // uses 400/200 per class via the ignored integration test.
        iterations: 300,
        ..Default::default()
    };

    // Try to load; on a missing cache, skip gracefully (no panic, exit 0).
    let train_raw = match load_train(&dir) {
        Ok(r) => r,
        Err(MnistError::Missing(p)) => return skip(&p),
        Err(e) => return skip_err(e),
    };
    let test_raw = match load_test(&dir) {
        Ok(r) => r,
        Err(MnistError::Missing(p)) => return skip(&p),
        Err(e) => return skip_err(e),
    };

    // 60/class train, 30/class test: a small, fast, real-data subset.
    let train = subset(&train_raw, 60, bcfg.cell, bcfg.grid);
    let test = subset(&test_raw, 30, bcfg.cell, bcfg.grid);

    println!("PhotonLayer — mnist_compression  (REAL MNIST, grid={}x{})", bcfg.grid, bcfg.grid);
    println!("  train={} test={}  sensor={}x{} (16x reduction)\n", train.len(), test.len(), bcfg.sensor, bcfg.sensor);

    let r = run_mnist_differential(&train, &test, &bcfg);

    println!("  Config A — optical compression vs full-image baseline (same tiny decoder):");
    println!("    full-image baseline : acc={:.3}  ({} px, {} params)", r.baseline_acc, r.baseline_pixels, r.baseline_decoder_params);
    println!("    optical compressed  : acc={:.3}  ({} px, {} params)", r.optical_acc, r.optical_sensor_pixels, r.decoder_params);
    println!("    sensor reduction    : {:.1}x     MAC reduction: {:.1}x", r.sensor_reduction_x, r.mac_reduction_x);
    println!("    Δ optical-baseline  : {:+.3} pp", r.optical_acc - r.baseline_acc);

    println!("\n  Config B — differential-detection lever (no decoder, same trained mask):");
    println!("    plain argmax I+      : acc={:.3}", r.config_b_plain);
    println!("    differential I+ - I- : acc={:.3}", r.config_b_differential);
    println!("    lever Δ              : {:+.3}", r.config_b_differential - r.config_b_plain);

    println!("\n  learned-vs-random differential (optics-only floor): {:.3} vs {:.3}",
        r.optics_only_differential, r.random_optics_only_differential);
    println!("\nNote: this small/fast subset under-performs the README's 400/200-per-class run.");
}

fn skip(missing: &std::path::Path) {
    println!("PhotonLayer — mnist_compression");
    println!("  MNIST cache not found: {}", missing.display());
    println!("  Skipping the real-data run (this is expected offline).\n");
    println!("  To enable it, place the four standard IDX files in:");
    println!("    {}", default_cache_dir().display());
    println!("  Files: train-images-idx3-ubyte, train-labels-idx1-ubyte,");
    println!("         t10k-images-idx3-ubyte,  t10k-labels-idx1-ubyte");
    println!("  (download + gunzip the MNIST IDX archives into that dir).");
}

fn skip_err(e: MnistError) {
    println!("PhotonLayer — mnist_compression");
    println!("  MNIST data present but unreadable: {e}");
    println!("  Skipping the real-data run.");
}

Example crates/photonlayer-bench/examples/multiplane_cascade.rs (full):
//! multiplane_cascade — stack diffractive phase planes, trained end-to-end.
//!
//! Stacking K phase planes separated by free-space propagation — a small
//! diffractive deep neural network (Lin/Ozcan) — and training all of them
//! jointly with the COMPOSED adjoint is the path past the single-plane ceiling.
//! This example trains a 1-plane and a 2-plane cascade on the synthetic shapes
//! with `train_cascade_grad`, which composes the SAME proven `backward_into` per
//! plane (the whole point: the adjoint composes, so D2NN backprop is just the
//! single-plane rule applied plane-by-plane).
//!
//! HONEST SCOPE (printed in the output too): the 4-class synthetic task is easy
//! enough that a single plane already saturates blind-test accuracy, so there is
//! no accuracy headroom for the 2nd plane to show here — the README's per-plane
//! accuracy GAIN (83% -> 88% single->two-plane) is a 10-class MNIST result. What
//! this example demonstrates honestly on synthetic data is: (1) the composed
//! adjoint TRAINS both cascades (loss falls), (2) the 2-plane reaches a LOWER
//! loss (more capacity), and (3) the second plane sees a genuinely DECORRELATED
//! field (|corr| ~ 0.06), so it is not redundant.
//!
//! What to look for in the output:
//!   * both cascades' CE loss falling, the 2-plane reaching a lower final loss,
//!   * the low inter-plane intensity correlation (the 2nd plane is not redundant).
//!
//! Run:
//!   cargo run --release --example multiplane_cascade -p photonlayer-bench

use photonlayer_bench::decoder::{pool_features, NearestCentroid};
use photonlayer_bench::grad_cascade::{train_cascade_grad, Cascade, CascadeSample, CascadeTrainConfig};
use photonlayer_bench::synthetic::{make_dataset, Sample, NUM_CLASSES};
use photonlayer_core::config::OpticalConfig;
use photonlayer_core::field::OpticalField;
use photonlayer_core::propagate::Propagator;

/// Incident fields + labels for the cascade trainer.
fn cascade_samples(samples: &[Sample], cfg: &OpticalConfig) -> Vec<CascadeSample> {
    samples.iter().map(|s| {
        let field = OpticalField::from_image(&s.image, cfg.width, cfg.height).expect("field");
        CascadeSample { u0: field.data, label: s.label }
    }).collect()
}

/// Blind-test accuracy of a trained cascade via the pooled NCC decoder. The
/// cascade's sensor intensity is pooled to `sensor x sensor`, L2-normalized
/// (matching the trainer's eval feature), and classified by nearest centroid.
fn cascade_acc(prop: &Propagator, theta: &[Vec<f32>], n: usize, sensor: usize,
               train: &[CascadeSample], test: &[CascadeSample]) -> f32 {
    let features = |set: &[CascadeSample]| -> (Vec<Vec<f32>>, Vec<usize>) {
        let casc = Cascade::new(prop, theta.to_vec(), n);
        let f = set.iter().map(|s| {
            let intensity = casc.intensity(&s.u0);
            // pool_features L2-normalizes, matching the trainer's NCC eval path.
            let side = (intensity.len() as f64).sqrt() as usize;
            pool_features(&intensity, side, side, sensor)
        }).collect();
        (f, set.iter().map(|s| s.label).collect())
    };
    let (tr_f, tr_l) = features(train);
    let (te_f, te_l) = features(test);
    NearestCentroid::fit(&tr_f, &tr_l, NUM_CLASSES).accuracy(&te_f, &te_l)
}

/// Train a `planes`-plane cascade; return (init_loss, final_loss, blind-acc, theta).
fn train_and_eval(prop: &Propagator, n: usize, sensor: usize, planes: usize,
                  train: &[CascadeSample], test: &[CascadeSample]) -> (f32, f32, f32, Vec<Vec<f32>>) {
    // Small-sigma init per plane (de-risked convergence, matches shipped code).
    let init: Vec<Vec<f32>> = (0..planes)
        .map(|p| {
            let seed = 0x6E157u64 ^ (p as u64).wrapping_mul(0x9E37_79B9);
            let m = photonlayer_core::mask::PhaseMask::random(n, n, seed);
            m.phase_radians.iter().map(|v| (v - core::f32::consts::PI) * 0.05).collect()
        })
        .collect();
    let cfg = CascadeTrainConfig { planes, epochs: 30, batch: 16, lr_mask: 0.04, lr_head: 0.05, sensor, seed: 0x6E157, raw_pool: false, adam_eps: 1e-7 };
    let out = train_cascade_grad(prop, n, n, train, &init, &cfg);
    let first = out.loss_curve.first().copied().unwrap_or(0.0);
    let last = out.loss_curve.last().copied().unwrap_or(0.0);
    let acc = cascade_acc(prop, &out.theta, n * n, sensor, train, test);
    (first, last, acc, out.theta)
}

/// Pearson |corr| between two equal-length vectors.
fn abs_corr(a: &[f32], b: &[f32]) -> f32 {
    let ma = a.iter().sum::<f32>() / a.len() as f32;
    let mb = b.iter().sum::<f32>() / b.len() as f32;
    let (mut cov, mut va, mut vb) = (0.0f32, 0.0f32, 0.0f32);
    for (x, y) in a.iter().zip(b) {
        cov += (x - ma) * (y - mb);
        va += (x - ma) * (x - ma);
        vb += (y - mb) * (y - mb);
    }
    let d = (va * vb).sqrt();
    if d > 1e-9 { (cov / d).abs() } else { 0.0 }
}

fn main() {
    let n = 16;
    let sensor = 4;
    let cfg = OpticalConfig::demo(n, n);
    let prop = Propagator::new(n, n, &cfg).expect("propagator");

    let data = make_dataset(n, 24, 0xCA5CADE);
    let (mut train_s, mut test_s) = (Vec::new(), Vec::new());
    for (i, s) in data.iter().enumerate() {
        if i % 2 == 0 { train_s.push(s.clone()); } else { test_s.push(s.clone()); }
    }
    let train = cascade_samples(&train_s, &cfg);
    let test = cascade_samples(&test_s, &cfg);

    println!("PhotonLayer — multiplane_cascade  (grid={n}x{n}, sensor={sensor}x{sensor})");
    println!("  train={} test={}  chance={:.3}\n", train.len(), test.len(), 1.0 / NUM_CLASSES as f32);

    let (f1, l1, a1, _t1) = train_and_eval(&prop, n, sensor, 1, &train, &test);
    println!("  1-plane: CE {f1:.4} -> {l1:.4}   blind-test acc = {a1:.3}");

    let (f2, l2, a2, t2) = train_and_eval(&prop, n, sensor, 2, &train, &test);
    println!("  2-plane: CE {f2:.4} -> {l2:.4}   blind-test acc = {a2:.3}");

    // Inter-plane decorrelation: compare the field intensity after plane 1 (a
    // 1-plane cascade of θ₀) to the field intensity after plane 2 (the full
    // 2-plane cascade), averaged over the training samples.
    let plane1 = Cascade::new(&prop, vec![t2[0].clone()], n * n);
    let plane2 = Cascade::new(&prop, t2.clone(), n * n);
    let mut sum = 0.0f32;
    for s in &train {
        sum += abs_corr(&plane1.intensity(&s.u0), &plane2.intensity(&s.u0));
    }
    let mean_corr = sum / train.len() as f32;

    println!("\n  2-plane reaches lower loss than 1-plane: {l2:.4} < {l1:.4} ({:+.4})", l2 - l1);
    println!("  inter-plane intensity |corr| = {mean_corr:.3}  (low => 2nd plane is NOT redundant)");
    println!("  blind-test accuracy here: 1-plane={a1:.3}, 2-plane={a2:.3} (Δ={:+.3})", a2 - a1);
    println!("    (both saturate on this easy 4-class task; the accuracy gain shows on MNIST,");
    println!("     where the README reports single-plane 83% -> two-plane 88%.)");
    println!("\nComposing the proven adjoint across planes trains a deeper diffractive network.");
}

Example crates/photonlayer-bench/examples/optical_feature_extractor.rs (full):
//! optical_feature_extractor — optics as an analog feature extractor.
//!
//! The claim (honestly scoped): holding the decoder fixed at a *tiny* weak
//! nearest-centroid head, a LEARNED optical measurement can be MORE linearly
//! separable than the raw input pixels fed to the same head. We freeze a mask
//! trained by hill-climbing, extract its compact optical features, and compare
//! the tiny decoder's blind-test accuracy on those features vs on the raw pooled
//! pixels (same decoder family, same feature dimension).
//!
//! HONEST CAVEAT (printed in the output too): nearest-centroid is a deliberately
//! weak baseline. This is a statement about feature SEPARABILITY under a fixed
//! weak decoder, NOT that optics beat digital methods — a small CNN on the raw
//! pixels would beat both. The point is that the analog transform front-loads
//! useful structure into far fewer numbers.
//!
//! What to look for in the output:
//!   * "optical features" decoder accuracy vs "raw pixels" decoder accuracy at
//!     the same tiny feature dimension, with the optical side higher, AND
//!   * the printed caveat that the baseline decoder is weak by design.
//!
//! Run:
//!   cargo run --release --example optical_feature_extractor -p photonlayer-bench

use photonlayer_bench::decoder::{pool_features, NearestCentroid};
use photonlayer_bench::learn::{learn_mask, LearnConfig};
use photonlayer_bench::pipeline::optical_feature_set;
use photonlayer_bench::synthetic::{make_dataset, Sample, NUM_CLASSES};
use photonlayer_core::config::OpticalConfig;

/// Raw-pixel features: each image average-pooled to feat x feat, L2-normalized.
fn raw_feature_set(samples: &[Sample], feat: usize) -> (Vec<Vec<f32>>, Vec<usize>) {
    let f = samples.iter()
        .map(|s| pool_features(&s.image.pixels, s.image.width, s.image.height, feat))
        .collect();
    (f, samples.iter().map(|s| s.label).collect())
}

fn main() {
    let n = 16;
    // Squeeze both feature sets to a TINY 2x2 = 4 numbers. At this compression
    // the raw pooled pixels lose class structure, but the learned optical
    // transform front-loads separable structure into the same 4 numbers. A
    // larger feat would let raw pixels saturate and hide the effect.
    let feat = 2;
    let cfg = OpticalConfig::demo(n, n);

    let data = make_dataset(n, 20, 0xFEA7);
    let (mut train, mut test) = (Vec::new(), Vec::new());
    for (i, s) in data.iter().enumerate() {
        if i % 2 == 0 { train.push(s.clone()); } else { test.push(s.clone()); }
    }

    println!("PhotonLayer — optical_feature_extractor  (grid={n}x{n}, feature={feat}x{feat})");
    println!("  train={} test={}  chance={:.3}\n", train.len(), test.len(), 1.0 / NUM_CLASSES as f32);

    // Decoder A: tiny centroid on RAW pooled pixels (no optics).
    let (r_tr_f, r_tr_l) = raw_feature_set(&train, feat);
    let (r_te_f, r_te_l) = raw_feature_set(&test, feat);
    let raw_dec = NearestCentroid::fit(&r_tr_f, &r_tr_l, NUM_CLASSES);
    let raw_acc = raw_dec.accuracy(&r_te_f, &r_te_l);

    // Freeze a learned optical mask, then decode its optical features with the
    // SAME tiny centroid family at the SAME feature dimension.
    let lc = LearnConfig { iterations: 250, feat_dim: feat, ..Default::default() };
    let outcome = learn_mask(&train, &cfg, &lc);
    let (o_tr_f, o_tr_l) = optical_feature_set(&train, &outcome.mask, &cfg, feat);
    let (o_te_f, o_te_l) = optical_feature_set(&test, &outcome.mask, &cfg, feat);
    let opt_dec = NearestCentroid::fit(&o_tr_f, &o_tr_l, NUM_CLASSES);
    let opt_acc = opt_dec.accuracy(&o_te_f, &o_te_l);

    let numbers = feat * feat;
    println!("  same tiny nearest-centroid decoder ({} params each):", raw_dec.param_count());
    println!("    raw pixels      ({feat}x{feat}={numbers} numbers): blind-test acc = {raw_acc:.3}");
    println!("    optical features({feat}x{feat}={numbers} numbers): blind-test acc = {opt_acc:.3}");
    println!("    optical - raw   = {:+.3}", opt_acc - raw_acc);

    println!("\n  CAVEAT (scientific honesty): nearest-centroid is a deliberately weak");
    println!("  decoder. This shows the LEARNED optical features are more linearly");
    println!("  separable under a FIXED weak head — not that optics beat digital. A");
    println!("  small CNN on the raw pixels would beat both. The analog transform");
    println!("  front-loads useful structure into the same tiny number of features.");
}

Example crates/photonlayer-bench/examples/privacy_probe.rs (full):
//! privacy_probe — a linear reconstruction attack on the optical measurement.
//!
//! When an optical mask diffuses and encodes the input before any pixel hits the
//! sensor, the raw detector pattern is not a human-readable image. To quantify
//! this we run a *reconstruction attack*: fit a ridge-regularized LINEAR inverse
//! map from the compact optical feature vector back to the (downsampled) input,
//! then measure how faithfully it reconstructs held-out images (PSNR, dB). An
//! identity mask (no optics) leaks heavily; a random/learned optical mask
//! scrambles the measurement, so the linear attack reconstructs poorly.
//!
//! HONEST CAVEAT (printed in the output too): this is a LINEAR lower bound on
//! leakage. A nonlinear attacker (e.g. a trained network) is expected to recover
//! more. Low linear-attack PSNR is evidence the measurement is not trivially the
//! image — it is NOT a privacy guarantee. Never imply privacy.
//!
//! What to look for in the output:
//!   * the identity (no-optics) mask leaking with HIGH reconstruction PSNR, and
//!   * the optical masks (random, learned) leaking LESS (lower PSNR / leakage),
//!     plus the explicit "linear lower bound, not a guarantee" caveat.
//!
//! Run:
//!   cargo run --release --example privacy_probe -p photonlayer-bench

use photonlayer_bench::learn::{learn_mask, LearnConfig};
use photonlayer_bench::privacy::privacy_leakage;
use photonlayer_bench::synthetic::make_dataset;
use photonlayer_core::config::OpticalConfig;
use photonlayer_core::mask::PhaseMask;

fn main() {
    let n = 16;
    let feat = 4; // keep the Gram matrix tiny (16x16 solve)
    let cfg = OpticalConfig::demo(n, n);

    let samples = make_dataset(n, 12, 0xCAFE);

    println!("PhotonLayer — privacy_probe  (linear reconstruction attack, grid={n}x{n})");
    println!("  attack: ridge-linear inverse  features -> {feat}x{feat} image; higher PSNR = more leakage\n");

    // 1. Identity mask = no optical processing -> detector ≈ input -> leaks.
    let identity = PhaseMask::identity(n, n);
    let id_rep = privacy_leakage(&samples, &identity, &cfg, feat);
    println!("  identity mask (NO optics):");
    println!("    reconstruction PSNR = {:>6.2} dB   leakage = {:.3}   |corr(frame,input)| = {:.3}",
        id_rep.reconstruction_psnr, id_rep.leakage_score, id_rep.frame_input_similarity);

    // 2. Random optical mask -> scrambled measurement.
    let random = PhaseMask::random(n, n, 0xDEAD);
    let rnd_rep = privacy_leakage(&samples, &random, &cfg, feat);
    println!("  random optical mask:");
    println!("    reconstruction PSNR = {:>6.2} dB   leakage = {:.3}   |corr(frame,input)| = {:.3}",
        rnd_rep.reconstruction_psnr, rnd_rep.leakage_score, rnd_rep.frame_input_similarity);

    // 3. Learned optical mask (frozen after hill-climb training).
    let lc = LearnConfig { iterations: 150, feat_dim: feat, ..Default::default() };
    let learned = learn_mask(&samples, &cfg, &lc).mask;
    let lrn_rep = privacy_leakage(&samples, &learned, &cfg, feat);
    println!("  learned optical mask:");
    println!("    reconstruction PSNR = {:>6.2} dB   leakage = {:.3}   |corr(frame,input)| = {:.3}",
        lrn_rep.reconstruction_psnr, lrn_rep.leakage_score, lrn_rep.frame_input_similarity);

    println!("\n  optical masks leak less under the LINEAR attack than the identity mask:");
    println!("    identity {:.2} dB -> random {:.2} dB ({:+.2}), learned {:.2} dB ({:+.2})",
        id_rep.reconstruction_psnr,
        rnd_rep.reconstruction_psnr, rnd_rep.reconstruction_psnr - id_rep.reconstruction_psnr,
        lrn_rep.reconstruction_psnr, lrn_rep.reconstruction_psnr - id_rep.reconstruction_psnr);

    println!("\n  CAVEAT: this is a LINEAR lower bound on leakage. A nonlinear attacker");
    println!("  (a trained network) is expected to recover more. Low linear-attack PSNR");
    println!("  shows the measurement is not trivially the image — it is NOT a privacy");
    println!("  guarantee. This is sim-only and makes no privacy claim.");
}

Test crates/photonlayer-bench/tests/cascade_gradient_check.rs (full):
//! End-to-end gradient check for the multi-plane diffractive cascade: the HARD
//! GATE that must pass before any cascade accuracy number is trusted (ADR-260).
//!
//! These validate that the cascade's composed adjoint (per-plane
//! [`Cascade::phase_grads`], built on `Propagator::backward_into` +
//! the proven `2·Im(conj·)` phase rule) is the exact gradient of the FULL CE
//! loss across BOTH phase planes, by central finite differences. They live as an
//! integration test (public API only) to keep `grad_cascade.rs` under the
//! 500-line limit, mirroring `photonlayer-core/tests/gradient_check.rs`.

use photonlayer_bench::grad_adam::{l2_normalize, softmax, Pooling};
use photonlayer_bench::grad_cascade::{
    head_forward_backward, train_cascade_grad, Cascade, CascadeSample, CascadeTrainConfig,
};
use photonlayer_bench::grad_train::LinearHead;
use photonlayer_core::complex::Complex;
use photonlayer_core::config::{OpticalConfig, PropagationMode};
use photonlayer_core::field::OpticalField;
use photonlayer_core::propagate::Propagator;

/// Seeded LCG in `[0,1)` (matches the single-plane FD check's generator).
fn rnd(s: &mut u64) -> f32 {
    *s = s
        .wrapping_mul(6364136223846793005)
        .wrapping_add(1442695040888963407);
    ((*s >> 40) as f32) / (1u32 << 24) as f32
}

/// THE HARD GATE: end-to-end finite-difference grad-check on the K=2 cascade CE
/// loss. Perturb θ entries across BOTH planes, central-difference the real CE
/// loss of a fixed (random) head + one labeled sample, and require the analytic
/// per-plane `∂L/∂θ` (composed adjoint) to match. Validates BOTH the
/// L2-normalized (eval-matched) and raw-pool feature paths. If this fails, no
/// cascade accuracy number is trustworthy.
#[test]

fn cascade_ce_gradient_matches_finite_difference() {
    let n_side = 16usize;
    let n = n_side * n_side;
    let mut cfg = OpticalConfig::demo(n_side, n_side);
    cfg.propagation = PropagationMode::AngularSpectrum;
    cfg.propagation_mm = 3.0;
    let prop = Propagator::new(n_side, n_side, &cfg).unwrap();
    let pool = Pooling::new(n_side, n_side, 4);
    let dim = pool.dim();

    let mut st = 0xC0FF_EE12_3456_789Au64;
    let u0: Vec<Complex> = (0..n)
        .map(|_| {
            let a = rnd(&mut st);
            let ph = (rnd(&mut st) - 0.5) * 0.5;
            Complex::from_phase(ph).scale(a)
        })
        .collect();
    // Two distinct phase planes.
    let theta0: Vec<f32> = (0..n).map(|_| rnd(&mut st) * core::f32::consts::TAU).collect();
    let theta1: Vec<f32> = (0..n).map(|_| rnd(&mut st) * core::f32::consts::TAU).collect();
    let planes = vec![theta0, theta1];

    let mut head = LinearHead::zeros(dim);
    head.w.iter_mut().for_each(|w| *w = (rnd(&mut st) - 0.5) * 0.8);
    head.b.iter_mut().for_each(|b| *b = (rnd(&mut st) - 0.5) * 0.2);
    let label = 1usize;

    for raw_pool in [false, true] {
        let cascade = Cascade::new(&prop, planes.clone(), n);
        let (v_planes, u_k) = cascade.forward_fields(&u0);
        let intensity: Vec<f32> = u_k.iter().map(|c| c.norm_sqr()).collect();
        let mut gw = vec![0.0f32; head.w.len()];
        let mut gb = vec![0.0f32; head.b.len()];
        let (_l0, w_pix) =
            head_forward_backward(&intensity, &pool, &head, label, raw_pool, &mut gw, &mut gb);
        let analytic = cascade.phase_grads(&v_planes, &u_k, &w_pix);

        // Pure CE loss as a function of the two θ planes (f64 reduction).
        let ce_loss = |p0: &[f32], p1: &[f32]| -> f64 {
            let c = Cascade::new(&prop, vec![p0.to_vec(), p1.to_vec()], n);
            let intensity = c.intensity(&u0);
            let mut f = pool.forward(&intensity);
            if !raw_pool {
                l2_normalize(&mut f);
            }
            let z = head.logits(&f);
            let p = softmax(&z);
            -(p[label].max(1e-30) as f64).ln()
        };

        // Central-difference loss with entry `kk` of plane `pl` perturbed.
        let fd_at = |pl: usize, kk: usize, eps: f64| -> f32 {
            let mut tp = planes.clone();
            let mut tm = planes.clone();
            tp[pl][kk] += eps as f32;
            tm[pl][kk] -= eps as f32;
            ((ce_loss(&tp[0], &tp[1]) - ce_loss(&tm[0], &tm[1])) / (2.0 * eps)) as f32
        };

        let eps = 1e-2f64;
        // Aggregate relative-L2 across BOTH planes, plus per-entry checks on the
        // dominant entries (matching the single-plane check's protocol).
        let gmax = analytic
            .iter()
            .flat_map(|g| g.iter())
            .fold(0.0f32, |m, &v| m.max(v.abs()));
        assert!(gmax > 1e-5, "raw_pool={raw_pool}: cascade gradient degenerate (all ~0)");
        let floor = 0.05 * gmax;

        let mut num = 0.0f64;
        let mut den = 0.0f64;
        for plane in 0..2 {
