        k2_acc - SINGLE_PLANE_GRAD_ACC,
        if k2_acc > SINGLE_PLANE_GRAD_ACC { "2-PLANE WINS" } else { "did not beat single-plane" }
    );
    eprintln!(
        "    3-plane - single-plane   {:>+7.4}   ({})",
